import re

_NUMBER_RE = re.compile(r'\d+(?:\.\d+)?')


def _tokenize(expr):
    tokens = []
    i, n = 0, len(expr)
    while i < n:
        c = expr[i]
        if c.isspace():
            i += 1
            continue
        if c.isdigit():
            m = _NUMBER_RE.match(expr, i)
            tokens.append(('NUM', float(m.group())))
            i = m.end()
            continue
        if c == '*' and i + 1 < n and expr[i + 1] == '*':
            tokens.append(('POW', '**'))
            i += 2
            continue
        if c in '+-*/()':
            tokens.append((c, c))
            i += 1
            continue
        raise ValueError(f"Illegal character {c!r} at position {i}")
    return tokens


class _Parser:
    def __init__(self, tokens):
        self.tokens = tokens
        self.pos = 0

    def _peek(self):
        return self.tokens[self.pos] if self.pos < len(self.tokens) else None

    def _advance(self):
        tok = self._peek()
        self.pos += 1
        return tok

    def parse_expr(self):
        value = self.parse_term()
        while True:
            tok = self._peek()
            if tok is None or tok[0] not in ('+', '-'):
                return value
            self._advance()
            rhs = self.parse_term()
            value = value + rhs if tok[0] == '+' else value - rhs

    def parse_term(self):
        value = self.parse_unary()
        while True:
            tok = self._peek()
            if tok is None or tok[0] not in ('*', '/'):
                return value
            self._advance()
            rhs = self.parse_unary()
            value = value * rhs if tok[0] == '*' else value / rhs

    def parse_unary(self):
        tok = self._peek()
        if tok is not None and tok[0] == '-':
            self._advance()
            return -self.parse_unary()
        return self.parse_power()

    def parse_power(self):
        base = self.parse_primary()
        tok = self._peek()
        if tok is not None and tok[0] == 'POW':
            self._advance()
            return base ** self.parse_unary()
        return base

    def parse_primary(self):
        tok = self._peek()
        if tok is None:
            raise ValueError("Unexpected end of expression")
        if tok[0] == 'NUM':
            self._advance()
            return tok[1]
        if tok[0] == '(':
            self._advance()
            value = self.parse_expr()
            if self._peek() is None or self._peek()[0] != ')':
                raise ValueError("Expected closing parenthesis")
            self._advance()
            return value
        raise ValueError(f"Unexpected token {tok[1]!r}")


def evaluate(expr: str) -> float:
    tokens = _tokenize(expr)
    if not tokens:
        raise ValueError("Empty expression")
    parser = _Parser(tokens)
    result = parser.parse_expr()
    if parser.pos != len(parser.tokens):
        raise ValueError(f"Unexpected token {parser._peek()[1]!r}")
    return float(result)
